        super(type, location, errors)
        @value = value
      end

      #: () -> serialized_whitespace_node
      def to_hash
        super.merge({
          value: value,
        }) #: Herb::serialized_whitespace_node
      end

      #: (Visitor) -> void
      def accept(visitor)
        visitor.visit_whitespace_node(self)
      end

      #: () -> Array[Herb::AST::Node?]
      def child_nodes
        []
      end

      #: () -> Array[Herb::AST::Node]
      def compact_child_nodes
        child_nodes.compact
      end

      #: () -> String
      def inspect
        tree_inspect.rstrip.gsub(/\s+$/, "")
      end

      #: (?Integer) -> String
      def tree_inspect(indent = 0)
        output = +""

        output += "@ #{node_name} "
        output += location.tree_inspect
        output += "\n"

        output += inspect_errors(prefix: "│   ")

        output += "└── value: "
        output += value ? value.tree_inspect : "∅"
        output += "\n"
        output += "\n"

        output.gsub(/^/, "    " * indent)
      end
    end

